-- Restaura somente saldos e historico financeiro do campeonato ativo a partir do backup Firebase de 21/07/2026.

begin;

create table if not exists public.balance_fix_20260721_teams_backup as select * from public.teams where false;
create table if not exists public.balance_fix_20260721_transactions_backup as select * from public.financial_transactions where false;

delete from public.financial_transactions where tournament_id='pn96b9k0w1jb';


update public.teams as t set budget=v.budget from (values
('5rs0uvc1ws9t',67::numeric),
('0tohjb43wske',34::numeric),
('73na9cafwsvb',36::numeric),
('y6sdlz5ewt7t',36::numeric),
('mtnv28zdwtk1',0::numeric),
('rc27249fa3tr',9::numeric)) as v(id,budget) where t.id=v.id and t.tournament_id='pn96b9k0w1jb';

commit;

select t.id,t.name,t.budget from public.teams t where t.tournament_id='pn96b9k0w1jb' order by t.source_order;
select count(*) as financial_transactions_restauradas from public.financial_transactions where tournament_id='pn96b9k0w1jb';